import{_ as o,o as a,c as t,a3 as n}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"75. Change Of Shift Allowance Pen And Mho","description":"","frontmatter":{"title":"75. Change Of Shift Allowance Pen And Mho","eba":"Mental Health Services 2024-2028","topics":["hours","shift-work","allowances"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/allowances/75-change-of-shift-allowance-pen-and-mho.md","filePath":"ebas/mental-health/rpn-pen-mho/allowances/75-change-of-shift-allowance-pen-and-mho.md"}'),l={name:"ebas/mental-health/rpn-pen-mho/allowances/75-change-of-shift-allowance-pen-and-mho.md"};function h(s,e,r,i,c,f){return a(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="_75-change-of-shift-allowance-pen-and-mho" tabindex="-1">75. Change Of Shift Allowance Pen And Mho <a class="header-anchor" href="#_75-change-of-shift-allowance-pen-and-mho" aria-label="Permalink to &quot;75. Change Of Shift Allowance Pen And Mho&quot;">​</a></h1><p><strong>75.1</strong> Calculation of change of shift allowance</p><p><strong>(a)</strong> For the purposes of clause 75.1(b), the change of shift allowance is calculated as the amount equal to 4% of the weekly rate of:</p><p><strong>(i)</strong> PEN Level 1 Year 1 for a PEN,</p><p><strong>(ii)</strong> MHO Level 1 Year 1 for a MHO.</p><p><strong>(b)</strong> For the purposes of this clause a change of shift previously occurred when a PEN/MHO changed from working one shift to another shift, the time of commencement of which shift differed by four hours or more from that of the first shift. Eligibility for ongoing change of shift allowance cap</p><p><strong>(c)</strong> Where an Employee was eligible immediately prior to the commencement of this Agreement, to receive the previously calculated change of shift allowance cap, they will continue to receive such an entitlement unless clause 75.1(b) applies.</p><p><strong>(d)</strong> The payment of the change of shift allowance cap will be maintained for each eligible Employee whilst employed by an Employer for the duration of this Agreement, unless the Employee:</p><p><strong>(i)</strong> chooses to work fixed shifts and never works shifts that would entitle the Employee to payment under this clause; or</p><p><strong>(ii)</strong> ceases to be employed as a PEN or MHO.</p><p><strong>(e)</strong> For the avoidance of doubt, Employees are not entitled to receive a cap on change of shift allowance if they commenced after 7 December 2012.</p>',11)])])}const g=o(l,[["render",h]]);export{m as __pageData,g as default};
